content.content:
   1→/* ── Mention node ── */
   2→.mention-node {
   3→    display: inline;
   4→}
   5→.mention-chip {
   6→    color: var(--accent-purple);
   7→    font-weight: 600;
   8→    cursor: pointer;
   9→    border-radius: 4px;
  10→    padding: 1px 2px;
  11→    transition: background-color 0.15s ease;
  12→}
  13→.mention-chip:hover {
  14→    background-color: rgba(139, 92, 246, 0.1);
  15→    text-decoration: underline;
  16→}
  17→.mention-chip--editing {
  18→    cursor: default;
  19→    background-color: rgba(139, 92, 246, 0.08);
  20→}
  21→.mention-chip--editing:hover {
  22→    text-decoration: none;
  23→}
  24→
  25→/* ── Mention autocomplete dropdown ── */
  26→.mention-dropdown {
  27→    position: fixed;
  28→    z-index: 200;
  29→    background: var(--bg-elevated);
  30→    border: 1px solid var(--border-light);
  31→    border-radius: 10px;
  32→    box-shadow: 0 8px 24px rgba(0, 0, 0, 0.15);
  33→    max-height: 280px;
  34→    overflow-y: auto;
  35→    min-width: 220px;
  36→    max-width: 320px;
  37→    padding: 4px;
  38→    backdrop-filter: blur(12px);
  39→}
  40→.mention-dropdown-item {
  41→    display: flex;
  42→    align-items: center;
  43→    gap: 10px;
  44→    padding: 8px 10px;
  45→    border-radius: 8px;
  46→    cursor: pointer;
  47→    transition: background-color 0.1s ease;
  48→}
  49→.mention-dropdown-item:hover,
  50→.mention-dropdown-item--selected {
  51→    background-color: var(--bg-secondary, rgba(139, 92, 246, 0.08));
  52→}
  53→.mention-dropdown-avatar {
  54→    width: 32px;
  55→    height: 32px;
  56→    border-radius: 50%;
  57→    object-fit: cover;
  58→    flex-shrink: 0;
  59→}
  60→.mention-dropdown-info {
  61→    display: flex;
  62→    flex-direction: column;
  63→    min-width: 0;
  64→}
  65→.mention-dropdown-name {
  66→    color: var(--text-primary);
  67→    font-weight: 600;
  68→    font-size: 0.9rem;
  69→    white-space: nowrap;
  70→    overflow: hidden;
  71→    text-overflow: ellipsis;
  72→}
  73→.mention-dropdown-username {
  74→    color: var(--text-muted);
  75→    font-size: 0.8rem;
  76→    white-space: nowrap;
  77→    overflow: hidden;
  78→    text-overflow: ellipsis;
  79→}
  80→
  81→/* ── Editor text formats ── */
  82→.editor-text-bold {
  83→    font-weight: bold;
  84→}
  85→.editor-text-italic {
  86→    font-style: italic;
  87→}
  88→.editor-text-underline {
  89→    text-decoration: underline;
  90→}
  91→
  92→/* ── Editor container variables (derived from global theme) ── */
  93→.editor-container {
  94→    --editor-bg: var(--bg-elevated);
  95→    --editor-surface: var(--bg-secondary);
  96→    --editor-text: var(--text-primary);
  97→    --editor-border: var(--border-light);
  98→    --editor-accent: var(--accent-purple);
  99→}
 100→
 101→/* ── Overlay backdrop ── */
 102→.editor-parent-container {
 103→    display: flex;
 104→    justify-content: center;
 105→    align-items: center;
 106→    position: absolute;
 107→    width: 100%;
 108→    height: 100%;
 109→    background-color: var(--bg-overlay);
 110→    backdrop-filter: blur(25px);
 111→    z-index: 130;
 112→}
 113→
 114→/* ── Main editor card ── */
 115→.editor-container {
 116→    display: flex;
 117→    flex-direction: column;
 118→    width: 100%;
 119→    max-width: 720px;
 120→    height: 80%;
 121→    min-height: 0;
 122→    overflow: hidden;
 123→    background-color: var(--editor-bg);
 124→    color: var(--editor-text);
 125→    border-radius: 16px;
 126→    padding: 1rem 1.5rem;
 127→    box-shadow: var(--shadow-modal);
 128→}
 129→
 130→.editor-mode-shell {
 131→    position: relative;
 132→    display: flex;
 133→    flex-direction: column;
 134→    flex: 1;
 135→    min-height: 0;
 136→    overflow: hidden;
 137→}
 138→
 139→/* ── Close button row ── */
 140→.editor-close-bttn-container {
 141→    display: flex;
 142→    width: 100%;
 143→    justify-content: flex-end;
 144→    align-items: center;
 145→}
 146→.editor-close-bttn {
 147→    display: flex;
 148→    align-items: center;
 149→    justify-content: center;
 150→    padding: 0.4rem;
 151→    border: none;
 152→    background: transparent;
 153→    border-radius: 50%;
 154→    cursor: pointer;
 155→    color: var(--text-muted);
 156→    transition: background-color 0.15s ease, color 0.15s ease, transform 0.15s ease;
 157→}
 158→.editor-close-bttn svg {
 159→    fill: var(--text-muted);
 160→    transition: fill 0.15s ease;
 161→}
 162→.editor-close-bttn:hover {
 163→    background-color: var(--bg-pill);
 164→    color: var(--editor-text);
 165→    transform: scale(1.05);
 166→}
 167→.editor-close-bttn:hover svg {
 168→    fill: var(--editor-text);
 169→}
 170→
 171→/* ── Title input ── */
 172→.content-title-input {
 173→    margin: 0.5rem 0;
 174→    border: none;
 175→    border-bottom: 2px solid transparent;
 176→    background-color: transparent;
 177→    font-size: 1.75rem;
 178→    font-weight: 650;
 179→    font-family: var(--font-serif);
 180→    padding: 0.5rem 0.25rem;
 181→    color: var(--editor-text);
 182→    transition: border-color 0.25s ease;
 183→}
 184→.content-title-input::placeholder {
 185→    color: var(--text-muted);
 186→}
 187→.content-title-input:focus {
 188→    outline: none;
 189→    border-bottom-color: var(--editor-accent);
 190→}
 191→
 192→/* ── Toolbar (above content) ── */
 193→.toolbar-wrapper {
 194→    display: flex;
 195→    align-items: center;
 196→    border-top: 1px solid var(--editor-border);
 197→    border-bottom: 1px solid var(--editor-border);
 198→    padding: 0.35rem 0;
 199→    margin-bottom: 0;
 200→    position: sticky;
 201→    top: 0;
 202→    z-index: 5;
 203→    background-color: var(--editor-bg);
 204→}
 205→.toolbar {
 206→    display: flex;
 207→    align-items: center;
 208→    gap: 2px;
 209→    width: 100%;
 210→    flex-wrap: wrap;
 211→}
 212→.group {
 213→    display: flex;
 214→    align-items: center;
 215→    gap: 2px;
 216→}
 217→.toolbar-divider {
 218→    width: 1px;
 219→    height: 20px;
 220→    background-color: var(--editor-border);
 221→    margin: 0 6px;
 222→    flex-shrink: 0;
 223→}
 224→.toolbar-bttns {
 225→    display: flex;
 226→    width: fit-content;
 227→    height: fit-content;
 228→    justify-content: center;
 229→    align-items: center;
 230→    padding: 0.4rem;
 231→    border-radius: 6px;
 232→    cursor: pointer;
 233→    transition: all 0.15s ease;
 234→    user-select: none;
 235→    color: var(--editor-text);
 236→}
 237→.toolbar-bttns svg {
 238→    fill: var(--editor-text);
 239→    transition: fill 0.15s ease;
 240→}
 241→.toolbar-bttns:hover {
 242→    background-color: var(--bg-pill);
 243→}
 244→.is-active {
 245→    display: flex;
 246→    justify-content: center;
 247→    align-items: center;
 248→    width: fit-content;
 249→    height: fit-content;
 250→    padding: 0.4rem;
 251→    border-radius: 6px;
 252→    cursor: pointer;
 253→    transition: all 0.15s ease;
 254→    user-select: none;
 255→    background-color: color-mix(in srgb, var(--editor-accent) 15%, transparent);
 256→}
 257→.is-active svg {
 258→    fill: var(--editor-accent);
 259→}
 260→
 261→/* ── Color pickers ── */
 262→.toolbar-color-picker {
 263→    position: relative;
 264→    display: flex;
 265→    align-items: center;
 266→}
 267→.toolbar-color-trigger {
 268→    display: inline-flex;
 269→    align-items: center;
 270→    gap: 6px;
 271→    padding: 0.35rem 0.45rem;
 272→    border-radius: 6px;
 273→    border: none;
 274→    background: transparent;
 275→    cursor: pointer;
 276→    color: var(--editor-text);
 277→    transition: background-color 0.15s ease;
 278→}
 279→.toolbar-color-trigger:hover {
 280→    background-color: var(--bg-pill);
 281→}
 282→.toolbar-color-icon {
 283→    font-weight: 700;
 284→    font-size: 0.9rem;
 285→    line-height: 1;
 286→}
 287→.toolbar-color-swatch {
 288→    width: 16px;
 289→    height: 4px;
 290→    border-radius: 3px;
 291→    border: 1px solid var(--editor-border);
 292→}
 293→.color-popover {
 294→    position: absolute;
 295→    top: calc(100% + 6px);
 296→    left: 0;
 297→    display: grid;
 298→    grid-template-columns: repeat(6, 18px);
 299→    gap: 6px;
 300→    padding: 8px;
 301→    background: var(--editor-bg);
 302→    border: 1px solid var(--editor-border);
 303→    border-radius: 8px;
 304→    box-shadow: var(--shadow-modal);
 305→    z-index: 12;
 306→}
 307→.color-swatch {
 308→    width: 18px;
 309→    height: 18px;
 310→    border-radius: 4px;
 311→    border: 1px solid var(--editor-border);
 312→    cursor: pointer;
 313→    background-color: transparent;
 314→}
 315→.color-swatch.is-default {
 316→    background-image:
 317→        linear-gradient(45deg, rgba(0, 0, 0, 0.15) 25%, transparent 25%),
 318→        linear-gradient(-45deg, rgba(0, 0, 0, 0.15) 25%, transparent 25%),
 319→        linear-gradient(45deg, transparent 75%, rgba(0, 0, 0, 0.15) 75%),
 320→        linear-gradient(-45deg, transparent 75%, rgba(0, 0, 0, 0.15) 75%);
 321→    background-size: 6px 6px;
 322→    background-position: 0 0, 0 3px, 3px -3px, -3px 0px;
 323→}
 324→.color-swatch.is-selected {
 325→    outline: 2px solid var(--editor-accent);
 326→    outline-offset: 1px;
 327→}
 328→
 329→/* ── Editor shell (flex-grow, scrollable) ── */
 330→.editor-shell {
 331→    position: relative;
 332→    flex: 1;
 333→    min-height: 0;
 334→    overflow-y: auto;
 335→    overflow-x: auto;
 336→    scrollbar-width: thin;
 337→    scrollbar-color: var(--text-muted) transparent;
 338→}
 339→.editor-shell::-webkit-scrollbar {
 340→    width: 6px;
 341→}
 342→.editor-shell::-webkit-scrollbar-thumb {
 343→    background: var(--text-muted);
 344→    border-radius: 4px;
 345→}
 346→.editor-shell::-webkit-scrollbar-track {
 347→    background-color: transparent;
 348→}
 349→
 350→/* ── Editor content area ── */
 351→.editor-text-container {
 352→    white-space: pre-wrap;
 353→    color: var(--editor-text);
 354→    padding: 1rem 0.5rem;
 355→}
 356→.editor-input {
 357→    font-synthesis: style;
 358→}
 359→.editor-input:focus {
 360→    outline: none;
 361→}
 362→.editor-placeholder {
 363→    color: var(--text-muted);
 364→    overflow: hidden;
 365→    position: absolute;
 366→    top: -4px;
 367→    user-select: none;
 368→    pointer-events: none;
 369→    margin: 0;
 370→}
 371→.editor-paragraph {
 372→    margin: 0;
 373→}
 374→.editor-heading-h1 {
 375→    margin: 0.9rem 0 0.45rem;
 376→    font-size: 1.75rem;
 377→    font-weight: 700;
 378→    line-height: 1.25;
 379→    color: var(--text-heading);
 380→}
 381→.editor-heading-h2 {
 382→    margin: 0.8rem 0 0.4rem;
 383→    font-size: 1.4rem;
 384→    font-weight: 650;
 385→    line-height: 1.3;
 386→    color: var(--text-heading);
 387→}
 388→.editor-heading-h3 {
 389→    margin: 0.7rem 0 0.35rem;
 390→    font-size: 1.15rem;
 391→    font-weight: 600;
 392→    line-height: 1.35;
 393→    color: var(--text-heading);
 394→}
 395→.editor-quote {
 396→    margin: 0.5rem 0;
 397→    padding: 0.3rem 0.65rem;
 398→    border-left: 2px solid var(--editor-accent);
 399→    background: color-mix(in srgb, var(--editor-accent) 5%, transparent);
 400→    color: var(--editor-text);
 401→    font-style: italic;
 402→}
 403→
 404→/* ── Footer bar (word count + save status + buttons) ── */
 405→.editor-footer {
 406→    display: flex;
 407→    justify-content: space-between;
 408→    align-items: center;
 409→    padding: 0.5rem 0;
 410→    border-top: 1px solid var(--editor-border);
 411→    margin-top: auto;
 412→    gap: 0.5rem;
 413→}
 414→.editor-footer-left {
 415→    display: flex;
 416→    align-items: center;
 417→    gap: 0.75rem;
 418→    min-width: 0;
 419→}
 420→.editor-footer-actions {
 421→    display: flex;
 422→    align-items: center;
 423→    gap: 0.5rem;
 424→    flex-shrink: 0;
 425→}
 426→.editor-word-count {
 427→    font-size: 0.8rem;
 428→    color: var(--text-muted);
 429→    user-select: none;
 430→    padding-left: 0.25rem;
 431→    white-space: nowrap;
 432→}
 433→.editor-save-status {
 434→    font-size: 0.75rem;
 435→    user-select: none;
 436→    white-space: nowrap;
 437→}
 438→.editor-save-status--saving {
 439→    color: var(--text-muted);
 440→}
 441→.editor-save-status--saved {
 442→    color: var(--text-muted);
 443→}
 444→.editor-save-status--unsaved {
 445→    color: var(--accent-amber, #d4a017);
 446→}
 447→
 448→/* ── Bar loader positioning ── */
 449→.editor-loader-wrapper {
 450→    height: 4px;
 451→    flex-shrink: 0;
 452→}
 453→
 454→/* ── Save button ── */
 455→.editor-save-bttn {
 456→    display: flex;
 457→    justify-content: center;
 458→    align-items: center;
 459→    padding: 0.5rem 1.25rem;
 460→    border-radius: 15px;
 461→    background-color: var(--editor-accent);
 462→    color: #ffffff;
 463→    font-weight: 650;
 464→    cursor: pointer;
 465→    border: none;
 466→    transition: background-color 0.15s ease, transform 0.1s ease, opacity 0.15s ease;
 467→}
 468→.editor-save-bttn:hover {
 469→    opacity: 0.9;
 470→}
 471→.editor-save-bttn:active {
 472→    transform: scale(0.98);
 473→}
 474→.editor-save-bttn:focus {
 475→    outline: none;
 476→}
 477→.editor-save-bttn-disabled {
 478→    display: flex;
 479→    justify-content: center;
 480→    align-items: center;
 481→    padding: 0.5rem 1.25rem;
 482→    border-radius: 15px;
 483→    background-color: var(--bg-pill);
 484→    color: var(--text-muted);
 485→    font-weight: 650;
 486→    user-select: none;
 487→    border: none;
 488→    cursor: not-allowed;
 489→}
 490→.editor-save-bttn-disabled:focus {
 491→    outline: none;
 492→}
 493→
 494→/* ── Draft button ── */
 495→.editor-draft-bttn {
 496→    display: flex;
 497→    justify-content: center;
 498→    align-items: center;
 499→    padding: 0.5rem 1rem;
 500→    border-radius: 15px;
 501→    background-color: transparent;
 502→    color: var(--editor-text);
 503→    font-weight: 600;
 504→    cursor: pointer;
 505→    border: 1.5px solid var(--editor-border);
 506→    transition: background-color 0.15s ease, border-color 0.15s ease, transform 0.1s ease;
 507→    font-size: 0.875rem;
 508→}
 509→.editor-draft-bttn:hover {
 510→    background-color: var(--bg-pill);
 511→    border-color: var(--text-muted);
 512→}
 513→.editor-draft-bttn:active {
 514→    transform: scale(0.98);
 515→}
 516→.editor-draft-bttn:focus {
 517→    outline: none;
 518→}
 519→.editor-draft-bttn-disabled {
 520→    display: flex;
 521→    justify-content: center;
 522→    align-items: center;
 523→    padding: 0.5rem 1rem;
 524→    border-radius: 15px;
 525→    background-color: transparent;
 526→    color: var(--text-muted);
 527→    font-weight: 600;
 528→    border: 1.5px solid var(--editor-border);
 529→    cursor: not-allowed;
 530→    opacity: 0.5;
 531→    font-size: 0.875rem;
 532→}
 533→.editor-draft-bttn-disabled:focus {
 534→    outline: none;
 535→}
 536→
 537→/* ── Image upload icon (inside toolbar) ── */
 538→.editor-upload-image-icon {
 539→    padding: 0.4rem;
 540→    border-radius: 6px;
 541→    cursor: pointer;
 542→    transition: all 0.15s ease;
 543→}
 544→.editor-upload-image-icon:hover {
 545→    background-color: var(--bg-pill);
 546→}
 547→
 548→/* ── Image components ── */
 549→.image-container {
 550→    display: flex;
 551→    justify-content: center;
 552→    width: 100%;
 553→    height: fit-content;
 554→}
 555→.image-wrapper {
 556→    position: relative;
 557→    display: flex;
 558→    justify-content: flex-end;
 559→    margin: 1rem 0;
 560→    width: fit-content;
 561→    height: fit-content;
 562→}
 563→.image-actions {
 564→    position: absolute;
 565→    display: flex;
 566→    gap: 0.3rem;
 567→    top: 0;
 568→    right: 0;
 569→    margin: 0.5rem;
 570→    z-index: 11;
 571→}
 572→.image-action-btn {
 573→    display: flex;
 574→    align-items: center;
 575→    justify-content: center;
 576→    padding: 0.4rem;
 577→    border-radius: 50%;
 578→    cursor: pointer;
 579→    transition: ease-in-out 0.1s;
 580→    background-color: rgba(0, 0, 0, 0.35);
 581→}
 582→.image-action-btn:hover {
 583→    background-color: rgba(0, 0, 0, 0.55);
 584→}
 585→.dimension-display {
 586→    position: absolute;
 587→    display: flex;
 588→    justify-content: center;
 589→    align-items: center;
 590→    top: -35px;
 591→    left: 50%;
 592→    transform: translateX(-50%);
 593→    background-color: var(--bg-pill);
 594→    color: var(--text-muted);
 595→    padding: 0.4rem 0.5rem;
 596→    white-space: nowrap;
 597→    pointer-events: none;
 598→    font-size: 0.8rem;
 599→    border-radius: 4px;
 600→}
 601→
 602→/* ── Resize handles ── */
 603→.southeast-side-handle {
 604→    position: absolute;
 605→    bottom: -4px;
 606→    right: -4px;
 607→    width: 12px;
 608→    height: 12px;
 609→    background-color: var(--bg-pill);
 610→    border: 1px solid var(--editor-text);
 611→    border-radius: 50%;
 612→    cursor: nwse-resize;
 613→    z-index: 10;
 614→}
 615→.southwest-side-handle {
 616→    position: absolute;
 617→    bottom: -4px;
 618→    left: -4px;
 619→    width: 12px;
 620→    height: 12px;
 621→    background-color: var(--bg-pill);
 622→    border: 1px solid var(--editor-text);
 623→    border-radius: 50%;
 624→    cursor: nesw-resize;
 625→    z-index: 10;
 626→}
 627→.northeast-side-handle {
 628→    position: absolute;
 629→    top: -4px;
 630→    right: -4px;
 631→    width: 12px;
 632→    height: 12px;
 633→    background-color: var(--bg-pill);
 634→    border: 1px solid var(--editor-text);
 635→    border-radius: 50%;
 636→    cursor: sw-resize;
 637→    z-index: 10;
 638→}
 639→.northwest-side-handle {
 640→    position: absolute;
 641→    top: -4px;
 642→    left: -4px;
 643→    width: 12px;
 644→    height: 12px;
 645→    background-color: var(--bg-pill);
 646→    border: 1px solid var(--editor-text);
 647→    border-radius: 50%;
 648→    cursor: se-resize;
 649→    z-index: 10;
 650→}
 651→.east-side-handle {
 652→    position: absolute;
 653→    top: 50%;
 654→    right: -4px;
 655→    width: 8px;
 656→    height: 20px;
 657→    background-color: var(--bg-pill);
 658→    border: 1px solid var(--editor-text);
 659→    border-radius: 2px;
 660→    transform: translateY(-50%);
 661→    cursor: ew-resize;
 662→    z-index: 10;
 663→}
 664→.south-side-handle {
 665→    position: absolute;
 666→    bottom: -4px;
 667→    left: 50%;
 668→    width: 20px;
 669→    height: 8px;
 670→    background-color: var(--bg-pill);
 671→    border: 1px solid var(--editor-text);
 672→    border-radius: 2px;
 673→    transform: translateX(-50%);
 674→    cursor: ns-resize;
 675→    z-index: 10;
 676→}
 677→.north-side-handle {
 678→    position: absolute;
 679→    top: -4px;
 680→    left: 50%;
 681→    width: 20px;
 682→    height: 8px;
 683→    background-color: var(--bg-pill);
 684→    border: 1px solid var(--editor-text);
 685→    border-radius: 2px;
 686→    transform: translateX(-50%);
 687→    cursor: nw-resize;
 688→    z-index: 10;
 689→}
 690→
 691→/* ── Image loading overlay ── */
 692→.image-loading-overlay {
 693→    position: absolute;
 694→    top: 0;
 695→    left: 0;
 696→    width: 100%;
 697→    height: 100%;
 698→    display: flex;
 699→    flex-direction: column;
 700→    justify-content: center;
 701→    align-items: center;
 702→    background-color: rgba(0, 0, 0, 0.45);
 703→    border-radius: 5px;
